SELECT id, gym_id, user_id, rating, content, created_at, updated_at
FROM gym_reviews
WHERE id = #{id}

SELECT EXISTS(
    SELECT 1 FROM gym_reviews WHERE gym_id = #{gymId} AND user_id = #{userId}
)

SELECT id, gym_id, user_id, rating, content, created_at, updated_at
FROM gym_reviews
WHERE gym_id = #{gymId}
ORDER BY created_at DESC, id DESC
LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE gym_reviews
SET rating = #{rating}, content = #{content}, updated_at = NOW()
WHERE id = #{id}
